// poliub-frontend/src/components/TelaAlunos.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import FormAluno from "./FormAluno"; // <-- aqui deve bater com o nome do arquivo que você criou

export default function TelaAlunos() {
  const [alunos, setAlunos] = useState([]);
  const [carregando, setCarregando] = useState(true);
  const [alunoEditando, setAlunoEditando] = useState(null);
  const { token } = JSON.parse(localStorage.getItem("user") || "{}"); // ou localStorage.getItem("token")

  // Função para recarregar lista de alunos
  const recarregarAlunos = async () => {
    setCarregando(true);
    try {
      const res = await axios.get("/api/alunos", {
        headers: { Authorization: `Bearer ${localStorage.getItem("token")}` },
      });
      setAlunos(res.data);
    } catch (err) {
      console.error("Erro ao buscar alunos:", err);
    } finally {
      setCarregando(false);
    }
  };

  useEffect(() => {
    recarregarAlunos();
  }, []);

  const handleEditarClick = (aluno) => {
    setAlunoEditando(aluno);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleFimEdicao = () => {
    setAlunoEditando(null);
  };

  const handleNovoAluno = () => {
    recarregarAlunos();
  };

  const handleDeletar = async (id) => {
    if (!window.confirm("Deseja realmente deletar este aluno?")) return;
    try {
      await axios.delete(`/api/alunos/${id}`, {
        headers: { Authorization: `Bearer ${localStorage.getItem("token")}` },
      });
      recarregarAlunos();
    } catch {
      alert("Erro ao deletar aluno");
    }
  };

  if (carregando) return <p>Carregando alunos...</p>;
  if (alunos.length === 0) return <p>Nenhum aluno cadastrado.</p>;

  return (
    <div className="mt-4">
      {/* Formulário de cadastro/edição no topo */}
      <FormAluno
        alunoEditando={alunoEditando}
        onNovoAluno={handleNovoAluno}
        onFimEdicao={handleFimEdicao}
      />

      <h2 className="text-xl font-semibold mb-4 text-[#1d3557]">
        Lista de Alunos
      </h2>

      {/* Cabeçalho de colunas */}
      <div className="flex px-5 pb-2 text-gray-500 font-bold text-sm">
        <div className="w-1/3">Nome</div>
        <div className="w-1/4">RA</div>
        <div className="w-1/4">Período</div>
        <div className="w-1/6 text-right">Ações</div>
      </div>

      {/* Cards/Listagem */}
      <ul className="space-y-3">
        {alunos.map((aluno) => (
          <li
            key={aluno.id}
            className="flex items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm hover:bg-gray-100 transition"
          >
            <div className="w-1/3 font-medium text-gray-800 truncate">
              {aluno.nome}
            </div>
            <div className="w-1/4 text-gray-600">{aluno.ra}</div>
            <div className="w-1/4 text-gray-500">
              {aluno.periodo_nome} ({aluno.turno})
            </div>
            <div className="w-1/6 flex justify-end space-x-2">
              <button
                onClick={() => handleEditarClick(aluno)}
                className="px-4 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
              >
                Editar
              </button>
              <button
                onClick={() => handleDeletar(aluno.id)}
                className="px-4 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
              >
                Deletar
              </button>
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
}
